import React, { useState } from 'react';
import { FiMessageSquare, FiSend } from 'react-icons/fi';
import { generateDynamicData } from '../../utils/dynamicData';
import { useUser } from '../../context/UserContext';

interface Props { skillId?: string; }

const AIMentorChat: React.FC<Props> = ({ skillId }) => {
  const { userProfile } = useUser();
  const data = generateDynamicData(skillId);
  const userField = (userProfile?.fieldOfExperience || userProfile?.learningGoals?.[0] || '').toLowerCase();

  const [messages, setMessages] = useState([
    { text: `Hi ${userProfile?.name || 'there'}! I'm your AI Mentor for ${data.skill}. How can I help you progress in ${data.skill}?`, isAi: true }
  ]);
  const [input, setInput] = useState('');

  const craftReply = (question: string) => {
    let base = `For ${data.skill}, a practical path is: ${data.quickStart}. `;
    if (data.decayRate) base += `With regular practice you can reduce skill decay (~${data.decayRate}%). `;

    if (userField.includes('data') || userField.includes('database') || userField.includes('ml')) {
      base += 'Given your background in data, focus on pipelines and data modelling first.';
    } else if (userField.includes('cloud') || userField.includes('devops')) {
      base += 'Given your cloud experience, pair this skill with a small deployment project to demonstrate end-to-end capability.';
    } else if (userField.includes('security') || userField.includes('cyber')) {
      base += 'Add security-aware practices and threat modelling while building projects.';
    } else if (userField) {
      base += `Try connecting ${data.skill} to your domain (${userField}) via a focused capstone project.`;
    } else {
      base += 'Start with fundamentals, follow the quick projects, and iterate.';
    }

    if (data.projectSuggestion) base += ` Suggested mini-project: ${data.projectSuggestion}.`;
    return base;
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;
    const question = input.trim();
    setMessages(prev => [...prev, { text: question, isAi: false }]);
    setInput('');

    setTimeout(() => {
      const reply = craftReply(question);
      setMessages(prev => [...prev, { text: reply, isAi: true }]);
    }, 700);
  };

  return (
    <div className="animate-fadeIn">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col h-[500px]">
        <div className="bg-slate-50 border-b border-gray-200 p-4">
          <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
            <FiMessageSquare className="text-blue-500" /> AI Career Mentor
          </h3>
        </div>

        <div className="flex-grow p-4 overflow-y-auto space-y-4 bg-white">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.isAi ? 'justify-start' : 'justify-end'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl ${
                msg.isAi ? 'bg-blue-50 text-blue-900 rounded-tl-none border border-blue-100' : 'bg-slate-800 text-white rounded-tr-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <form onSubmit={handleSend} className="p-4 bg-gray-50 border-t border-gray-200 flex gap-2">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask about your learning path..."
            className="flex-grow bg-white border border-gray-300 rounded-xl px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
          />
          <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-xl transition-colors shadow-sm">
            <FiSend />
          </button>
        </form>
      </div>
    </div>
  );
};

export default AIMentorChat;
